const uniqueProfiles = new Map();
const allItems = $input.all();

// --- Get the 'parent' value from the "If1" node ---
const parentValue = $('If1').first().json.profile_url || null;

// --- Get the 'post_url' value from the input ---
// This logic is still correct and will find the post URL from any item type
const firstItemWithPost = allItems.find(item => (item.json.query && item.json.query.post) || item.json.postUrl);
const postUrlValue = firstItemWithPost ? (firstItemWithPost.json.query ? firstItemWithPost.json.query.post : firstItemWithPost.json.postUrl) : null;

// Helper function to process and add a profile to our map
const addOrUpdateProfile = (profileUrl, contactInfo, engagement) => {
  if (!profileUrl) {
    // Skip if the profile URL is null or invalid (e.g., private profiles)
    return;
  }

  if (!uniqueProfiles.has(profileUrl)) {
    // If we haven't seen this person before, create a new entry
    uniqueProfiles.set(profileUrl, {
      contact: contactInfo,
      engagements: [] // Start with an empty list of engagements
    });
  }

  // Get the person's record
  const existingProfile = uniqueProfiles.get(profileUrl);

  // --- Generic contact info merging ---
  // This loop will update any field in 'contact' (like headline, urn, etc.)
  // if the new data has it and the existing record doesn't (i.e., it's null).
  for (const key in contactInfo) {
    if (contactInfo[key] && !existingProfile.contact[key]) {
      existingProfile.contact[key] = contactInfo[key];
    }
  }

  // Add the new engagement to this person's record
  if (engagement) {
    existingProfile.engagements.push(engagement);
  }
};

// Loop through all incoming items
for (const item of allItems) {
  const json = item.json; // Use json variable for clarity

  // --- Part 1: Process Reactors (Likers) ---
  // Check for 'reactionType' as the unique key for reactors
  if (json.reactionType && json.actor && json.actor.linkedinUrl) {
    const reactor = json.actor;
    const profileUrl = reactor.linkedinUrl;

    const contactInfo = {
      name: reactor.name,
      headline: reactor.position || null,
      profileUrl: profileUrl,
      urn: reactor.id || null
    };

    const engagement = {
      type: 'reaction',
      value: json.reactionType || 'UNKNOWN'
    };

    addOrUpdateProfile(profileUrl, contactInfo, engagement);
  }

  // --- NEW: Part 2: Process NEW Comment Items (Top-level) ---
  // Check for 'commentary' as the unique key for new comment items
  else if (json.commentary && json.actor && json.actor.linkedinUrl) {
    const author = json.actor;
    const profileUrl = author.linkedinUrl;

    const contactInfo = {
      name: author.name,
      headline: author.position || null, // New comments have 'position'
      profileUrl: profileUrl,
      urn: author.id || null // New comments have 'id'
    };

    const engagement = {
      type: 'comment',
      value: json.commentary || '' // Use 'commentary' for the text
    };

    addOrUpdateProfile(profileUrl, contactInfo, engagement);

    // --- NEW: Process replies within this comment item ---
    if (json.replies && Array.isArray(json.replies)) {
      for (const reply of json.replies) {
        if (reply.actor && reply.actor.linkedinUrl) {
          const replyAuthor = reply.actor;
          const replyProfileUrl = replyAuthor.linkedinUrl;

          const replyContactInfo = {
            name: replyAuthor.name,
            headline: replyAuthor.position || null,
            profileUrl: replyProfileUrl,
            urn: replyAuthor.id || null
          };

          const replyEngagement = {
            type: 'comment_reply', // Differentiate it from a base comment
            value: reply.commentary || ''
          };

          addOrUpdateProfile(replyProfileUrl, replyContactInfo, replyEngagement);
        }
      }
    }
  }

  // --- Part 3: Process OLD Comment Items (Array) ---
  // This is the original logic for the old format (comment containers)
  else if (json.comments && Array.isArray(json.comments)) {
    for (const comment of json.comments) {
      // This check will correctly skip comments where author.profileUrl is null
      if (comment.author && comment.author.profileUrl) {
        const author = comment.author;
        const profileUrl = author.profileUrl;

        const contactInfo = {
          name: author.name,
          headline: null, // Old format didn't have headline
          profileUrl: profileUrl,
          urn: author.urn || null
        };

        const engagement = {
          type: 'comment',
          value: comment.text || ''
        };

        addOrUpdateProfile(profileUrl, contactInfo, engagement);
      }
    }
  }
}

// Convert the Map's values into an array
const finalProfiles = Array.from(uniqueProfiles.values());

// --- Map over the results to add the 'parent' and 'post_url' values ---
return finalProfiles.map(profile => {
  return {
    parent: parentValue,     // Add the parent field
    post_url: postUrlValue, // Add the new post_url field
    ...profile             // Spread the existing { contact, engagements }
  };
});
